import{_ as o,o as a,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Deploy on Railway","description":"","frontmatter":{"title":"Deploy on Railway"},"headers":[],"relativePath":"install/railway.md","filePath":"install/railway.md","lastUpdated":null}'),l={name:"install/railway.md"};function r(n,e,s,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i('<p>Deploy OpenSoul on Railway with a one-click template and finish setup in your browser. This is the easiest “no terminal on the server” path: Railway runs the Gateway for you, and you configure everything via the <code>/setup</code> web wizard.</p><h2 id="quick-checklist-new-users" tabindex="-1"><a class="header-anchor" href="#quick-checklist-new-users">#</a> Quick checklist (new users)</h2><ol><li>Click <strong>Deploy on Railway</strong> (below).</li><li>Add a <strong>Volume</strong> mounted at <code>/data</code>.</li><li>Set the required <strong>Variables</strong> (at least <code>SETUP_PASSWORD</code>).</li><li>Enable <strong>HTTP Proxy</strong> on port <code>8080</code>.</li><li>Open <code>https://&lt;your-railway-domain&gt;/setup</code> and finish the wizard.</li></ol><h2 id="one-click-deploy" tabindex="-1"><a class="header-anchor" href="#one-click-deploy">#</a> One-click deploy</h2><a href="https://railway.com/deploy/opensoul-railway-template" target="_blank" rel="noreferrer"> Deploy on Railway </a><p>After deploy, find your public URL in <strong>Railway → your service → Settings → Domains</strong>.</p><p>Railway will either:</p><ul><li>give you a generated domain (often <code>https://&lt;something&gt;.up.railway.app</code>), or</li><li>use your custom domain if you attached one.</li></ul><p>Then open:</p><ul><li><code>https://&lt;your-railway-domain&gt;/setup</code> — setup wizard (password protected)</li><li><code>https://&lt;your-railway-domain&gt;/opensoul</code> — Control UI</li></ul><h2 id="what-you-get" tabindex="-1"><a class="header-anchor" href="#what-you-get">#</a> What you get</h2><ul><li>Hosted OpenSoul Gateway + Control UI</li><li>Web setup wizard at <code>/setup</code> (no terminal commands)</li><li>Persistent storage via Railway Volume (<code>/data</code>) so config/credentials/workspace survive redeploys</li><li>Backup export at <code>/setup/export</code> to migrate off Railway later</li></ul><h2 id="required-railway-settings" tabindex="-1"><a class="header-anchor" href="#required-railway-settings">#</a> Required Railway settings</h2><h3 id="public-networking" tabindex="-1"><a class="header-anchor" href="#public-networking">#</a> Public Networking</h3><p>Enable <strong>HTTP Proxy</strong> for the service.</p><ul><li>Port: <code>8080</code></li></ul><h3 id="volume-required" tabindex="-1"><a class="header-anchor" href="#volume-required">#</a> Volume (required)</h3><p>Attach a volume mounted at:</p><ul><li><code>/data</code></li></ul><h3 id="variables" tabindex="-1"><a class="header-anchor" href="#variables">#</a> Variables</h3><p>Set these variables on the service:</p><ul><li><code>SETUP_PASSWORD</code> (required)</li><li><code>PORT=8080</code> (required — must match the port in Public Networking)</li><li><code>OPENSOUL_STATE_DIR=/data/.opensoul</code> (recommended)</li><li><code>OPENSOUL_WORKSPACE_DIR=/data/workspace</code> (recommended)</li><li><code>OPENSOUL_GATEWAY_TOKEN</code> (recommended; treat as an admin secret)</li></ul><h2 id="setup-flow" tabindex="-1"><a class="header-anchor" href="#setup-flow">#</a> Setup flow</h2><ol><li>Visit <code>https://&lt;your-railway-domain&gt;/setup</code> and enter your <code>SETUP_PASSWORD</code>.</li><li>Choose a model/auth provider and paste your key.</li><li>(Optional) Add Telegram/Discord/Slack tokens.</li><li>Click <strong>Run setup</strong>.</li></ol><p>If Telegram DMs are set to pairing, the setup wizard can approve the pairing code.</p><h2 id="getting-chat-tokens" tabindex="-1"><a class="header-anchor" href="#getting-chat-tokens">#</a> Getting chat tokens</h2><h3 id="telegram-bot-token" tabindex="-1"><a class="header-anchor" href="#telegram-bot-token">#</a> Telegram bot token</h3><ol><li>Message <code>@BotFather</code> in Telegram</li><li>Run <code>/newbot</code></li><li>Copy the token (looks like <code>123456789:AA...</code>)</li><li>Paste it into <code>/setup</code></li></ol><h3 id="discord-bot-token" tabindex="-1"><a class="header-anchor" href="#discord-bot-token">#</a> Discord bot token</h3><ol><li>Go to <a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">https://discord.com/developers/applications</a></li><li><strong>New Application</strong> → choose a name</li><li><strong>Bot</strong> → <strong>Add Bot</strong></li><li><strong>Enable MESSAGE CONTENT INTENT</strong> under Bot → Privileged Gateway Intents (required or the bot will crash on startup)</li><li>Copy the <strong>Bot Token</strong> and paste into <code>/setup</code></li><li>Invite the bot to your server (OAuth2 URL Generator; scopes: <code>bot</code>, <code>applications.commands</code>)</li></ol><h2 id="backups-migration" tabindex="-1"><a class="header-anchor" href="#backups-migration">#</a> Backups &amp; migration</h2><p>Download a backup at:</p><ul><li><code>https://&lt;your-railway-domain&gt;/setup/export</code></li></ul><p>This exports your OpenSoul state + workspace so you can migrate to another host without losing config or memory.</p>',34)])])}const g=o(l,[["render",r]]);export{u as __pageData,g as default};
